class UsersRepository {
    private final ApiService apiService;

    UsersRepository(ApiService apiService) {
        this.apiService = apiService;
    }

    void fetchUsers(Callback<List<User>> callback) {
        apiService.getUsers().enqueue(callback);
    }
}

class UsersActivity extends AppCompatActivity {
    private TextView textView;
    private UsersRepository repository;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        textView = new TextView(this);
        textView.setPadding(32, 32, 32, 32);
        setContentView(textView);

        repository = new UsersRepository(MyApp.api());
        loadUsers();
    }

    private void loadUsers() {
        textView.setText("Loading users...");
        repository.fetchUsers(new Callback<List<User>>() {
            @Override
            public void onResponse(@NonNull Call<List<User>> call, @NonNull Response<List<User>> response) {
                if (response.isSuccessful() && response.body() != null) {
                    StringBuilder sb = new StringBuilder();
                    for (User user : response.body()) {
                        sb.append(user.id).append(" - ").append(user.name).append(" <").append(user.email).append(">\n");
                    }
                    textView.setText(sb.toString());
                } else {
                    textView.setText("Failed to load users: " + response.code());
                }
            }

            @Override
            public void onFailure(@NonNull Call<List<User>> call, @NonNull Throwable t) {
                textView.setText("Error: " + t.getMessage());
            }
        });
    }
}

